"use client";
import { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import { AuthContext } from '@/context/AuthContext';
import { useRouter } from 'next/navigation';
import { Loader2, Trash2, Edit3, Save, X } from 'lucide-react';

export default function ProfilePage() {
  const { user, token } = useContext(AuthContext);
  const router = useRouter();
  
  const [myPosts, setMyPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  
  // סטייטים לעריכת פוסט
  const [editingPostId, setEditingPostId] = useState(null);
  const [editTitle, setEditTitle] = useState("");
  const [editContent, setEditContent] = useState("");

  useEffect(() => {
    // הגנה על העמוד - רק משתמשים מחוברים יכולים להיכנס
    if (!token && !user) {
      router.push('/');
      return;
    }

    const fetchMyPosts = async () => {
      try {
        // מושכים את כל פוסטים הקהילה ומסננים רק את אלו של המשתמש הנוכחי
        const res = await axios.get(`${process.env.NEXT_PUBLIC_API_URL}/community-posts`);
        const userPosts = res.data.filter(post => post.author._id === user.id);
        setMyPosts(userPosts);
      } catch (error) {
        console.error("שגיאה במשיכת הפוסטים שלי:", error);
      } finally {
        setLoading(false);
      }
    };

    if (user) fetchMyPosts();
  }, [user, token, router]);

  // פונקציית מחיקה
  const handleDelete = async (postId) => {
    if (!window.confirm("האם אתה בטוח שברצונך למחוק את הפוסט הזה?")) return;
    
    try {
      await axios.delete(`${process.env.NEXT_PUBLIC_API_URL}/community-posts/${postId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      // מעדכנים את המסך ומעלימים את הפוסט שנמחק
      setMyPosts(myPosts.filter(post => post._id !== postId));
    } catch (error) {
      console.error("שגיאה במחיקת הפוסט:", error);
      alert("לא ניתן למחוק את הפוסט כרגע.");
    }
  };

  // פונקציות עריכה
  const startEditing = (post) => {
    setEditingPostId(post._id);
    setEditTitle(post.title);
    setEditContent(post.content);
  };

  const cancelEditing = () => {
    setEditingPostId(null);
    setEditTitle("");
    setEditContent("");
  };

  const handleUpdate = async (postId) => {
    try {
      const res = await axios.put(`${process.env.NEXT_PUBLIC_API_URL}/community-posts/${postId}`, 
        { title: editTitle, content: editContent },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      
      // מעדכנים את רשימת הפוסטים עם המידע החדש שחזר מהשרת
      setMyPosts(myPosts.map(post => post._id === postId ? { ...post, title: editTitle, content: editContent } : post));
      setEditingPostId(null);
    } catch (error) {
      console.error("שגיאה בעדכון הפוסט:", error);
      alert("שגיאה בעדכון הפוסט.");
    }
  };

  if (loading) {
    return <div className="min-h-screen flex justify-center items-center"><Loader2 className="w-12 h-12 animate-spin text-indigo-500" /></div>;
  }

  return (
    <main className="min-h-screen bg-slate-50 py-12 px-4 md:px-8">
      <div className="max-w-4xl mx-auto">
        
        {/* אזור פרטי משתמש */}
        <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 flex items-center gap-6 mb-12">
          <img src={user?.avatarUrl} alt="profile" className="w-24 h-24 rounded-full border-4 border-indigo-50 shadow-sm" />
          <div>
            <h1 className="text-3xl font-black text-slate-900 mb-1">{user?.username}</h1>
            <p className="text-slate-500">{user?.email}</p>
            <span className="inline-block mt-2 bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full text-sm font-semibold">
              {user?.role === 'admin' ? 'מנהל מערכת' : 'חבר קהילה'}
            </span>
          </div>
        </div>

        <h2 className="text-2xl font-bold text-slate-800 mb-6">הפוסטים שלי ({myPosts.length})</h2>

        <div className="flex flex-col gap-6">
          {myPosts.length === 0 ? (
            <div className="text-center py-12 bg-white rounded-2xl border border-slate-100 text-slate-500">
              עדיין לא פרסמת שום פוסט בקהילה.
            </div>
          ) : (
            myPosts.map(post => (
              <div key={post._id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 transition hover:shadow-md">
                
                {editingPostId === post._id ? (
                  /* מצב עריכה */
                  <div className="flex flex-col gap-4">
                    <input 
                      type="text" 
                      value={editTitle} 
                      onChange={(e) => setEditTitle(e.target.value)} 
                      className="text-xl font-bold bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                    <textarea 
                      value={editContent} 
                      onChange={(e) => setEditContent(e.target.value)} 
                      rows="4"
                      className="bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none resize-none"
                    />
                    <div className="flex gap-3 justify-end mt-2">
                      <button onClick={cancelEditing} className="flex items-center gap-1 text-slate-500 hover:text-slate-700 px-4 py-2 font-medium">
                        <X className="w-4 h-4" /> ביטול
                      </button>
                      <button onClick={() => handleUpdate(post._id)} className="flex items-center gap-1 bg-emerald-500 hover:bg-emerald-600 text-white px-5 py-2 rounded-xl font-medium transition">
                        <Save className="w-4 h-4" /> שמור שינויים
                      </button>
                    </div>
                  </div>
                ) : (
                  /* מצב תצוגה רגיל */
                  <>
                    <div className="flex justify-between items-start mb-2">
                      <h3 className="text-xl font-bold text-slate-900">{post.title}</h3>
                      <div className="flex gap-2">
                        <button onClick={() => startEditing(post)} className="text-slate-400 hover:text-indigo-500 transition p-2 bg-slate-50 rounded-lg">
                          <Edit3 className="w-5 h-5" />
                        </button>
                        <button onClick={() => handleDelete(post._id)} className="text-slate-400 hover:text-rose-500 transition p-2 bg-slate-50 rounded-lg">
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                    <p className="text-slate-600 whitespace-pre-wrap">{post.content}</p>
                    <div className="text-xs text-slate-400 mt-4">
                      פורסם ב: {new Date(post.createdAt).toLocaleDateString('he-IL')}
                    </div>
                  </>
                )}
                
              </div>
            ))
          )}
        </div>

      </div>
    </main>
  );
}